y₂'' = A a₀ \frac{1}{x} + \sum_{k=0}^{\infty} k(k-1) b_k x^{k-2} = A a₀ \frac{1}{x} + \sum_{k=2}^{\infty} k(k-1) b_k x^{k-2}

k \to k+2 \quad = A a₀ \frac{1}{x} + \sum_{k=0}^{\infty} (k+2)(k+1) b_{k+2} x^{k}

\frac{y₂}{x} = A a₀ \ln x + \sum_{k=0}^{\infty} b_k x^{k-1}

= A a₀ \ln x + \frac{b₀}{x} + \sum_{k=0}^{\infty} b_{k+1} x^{k}

y₂'' - y₂' + \frac{1}{x} y₂ = 0 \Rightarrow

A a₀ \frac{1}{x} + \sum_{k=0}^{\infty} (k+2)(k+1) b_{k+2} x^{k} - A a₀ (\ln x + 1) - \sum_{k=0}^{\infty} (k+1) b_{k+1} x^{k}

+ A a₀ \ln x + \frac{b₀}{x} + \sum_{k=0}^{\infty} b_{k+1} x^{k} = 0

0 \ln x + \frac{A a₀ + b₀}{x} - A a₀ + \sum_{k=0}^{\infty} \left[ (k+2)(k+1) b_{k+2} - (k+1) b_{k+1} + b_{k+1} \right] x^{k} = 0

\frac{A a₀ + b₀}{x} + 2 b₂ - A a₀ + \sum_{k=1}^{\infty} \left[ (k+2)(k+1) b_{k+2} - k b_{k+1} \right] x^{k} = 0

\Rightarrow \begin{cases} 
A a₀ + b₀ = 0 \Rightarrow b₀ = -A a₀ \\
2 b₂ - A a₀ = 0 \Rightarrow b₂ = +\frac{1}{2} A a₀ \\
(k+2)(k+1) b_{k+2} - k b_{k+1} = 0 \ (k \ge 1)
\end{cases}

b_{k+2} = \frac{k}{(k+2)(k+1)} b_{k+1} \ (k \ge 1)

b₃ = \frac{1}{3 \cdot 2} b₂

b₄ = \frac{2}{4 \cdot 3} \cdot b₃ = \frac{2}{4 \cdot 3} \cdot \frac{1}{3 \cdot 2} b₂ = \frac{2! \cdot 2}{4! \cdot 3!}

b₅ = \frac{3}{5 \cdot 4} b₄ = \frac{3}{5 \cdot 4} \cdot \frac{2}{4 \cdot 3} \cdot \frac{1}{3 \cdot 2} b₂ = \frac{3! \cdot 2}{5! \cdot 4!}

b₆ = \frac{4}{6 \cdot 5} b₅ = \frac{4}{6 \cdot 5} \cdot \frac{3}{5 \cdot 4} \cdot \frac{2}{4 \cdot 3} \cdot \frac{1}{3 \cdot 2} b₂ = \frac{4!}{6! \cdot 5!} = \frac{4! \cdot 2}{6! \cdot 5!}

